/**
 * All REST collection names known to the API (typed entities + action-only
 * endpoints like Version/ZoneInformation/Authenticate). This is a strict
 * superset of `EntityName` (the queryable, typed collections used by the
 * client surfaces). Use `EntityName`/`TypedCollectionName` when you need a
 * collection that has a generated entity interface.
 */
export type CollectionName = keyof typeof AUTOTASK_COLLECTIONS;

/** Collection names that have a generated entity interface (typed === true). */
export type TypedCollectionName = {
  [K in CollectionName]: (typeof AUTOTASK_COLLECTIONS)[K]["typed"] extends true ? K : never;
}[CollectionName];

/** Array of every collection name. */
export const COLLECTION_NAMES = Object.keys(AUTOTASK_COLLECTIONS) as CollectionName[];

